import torch, torch.nn as nn; from torchdiffeq import odeint; class CNF(nn.Module): 
   def __init__(s,d=2,h=64): super().__init__(); s.net=nn.Sequential(nn.Linear(d,h),nn.Tanh(),nn.Linear(h,h),nn.Tanh(),nn.Linear(h,d)) 
   def forward(s,t,st): 
     z=st[0] 
     with torch.enable_grad(): 
       z.requires_grad_(True); dz=s.net(z); eps=torch.randn_like(z) 
       div=(torch.autograd.grad((dz*eps).sum(), z, create_graph=True)[0]*eps).sum(1) 
     return (dz, -div) 
