import torch; import torch.nn as nn; import torch.nn.functional as F; ns=dict(torch=torch,nn=nn,F=F,__builtins__=__import__("builtins").__dict__); __import__("builtins").exec('class ChromBPNet(nn.Module):
    def __init__(self,num_tasks=1,num_filters=64,num_layers=4):
        super().__init__(); self.stem=nn.Conv1d(4,num_filters,21,padding=10); self.dil=nn.ModuleList([nn.Conv1d(num_filters,num_filters,3,padding=2**i,dilation=2**i) for i in range(num_layers)]); self.profile=nn.Conv1d(num_filters,num_tasks*2,75,padding=37); self.count=nn.Linear(num_filters,num_tasks)
    def forward(self,x):
        h=F.relu(self.stem(x))
