import torch; import torch.nn as nn; exec('class TemporalUnet(nn.Module):
    def __init__(self, transition_dim=17, cond_dim=17, dim=64):
        super().__init__(); self.down1=nn.Conv1d(transition_dim, dim, 3, padding=1); self.down2=nn.Conv1d(dim, dim*2, 4, stride=2, padding=1); self.mid=nn.Conv1d(dim*2, dim*2, 3, padding=1); self.up=nn.ConvTranspose1d(dim*2, dim, 4, stride=2, padding=1); self.out=nn.Conv1d(dim*2, transition_dim, 3, padding=1)
    def forward(self, x):
        y=x.transpose(1,2); skip=torch.relu(self.down1(y)); y=torch.relu(self.down2(skip)); y=torch.relu(self.mid(y)); y=torch.relu(self.up(y)); return self.out(torch.cat([y, skip], 1)).transpose(1,2)
'); model=TemporalUnet(transition_dim=17, cond_dim=17, dim=64)

import torch; import torch.nn as nn; exec('class TinyRARE(nn.Module):
    def __init__(self, num_class=37):
        super().__init__()
        self.cnn = nn.Sequential(nn.Conv2d(1,32,3,padding=1), nn.ReLU(), nn.MaxPool2d(2), nn.Conv2d(32,64,3,padding=1), nn.ReLU(), nn.MaxPool2d((2,1)), nn.Conv2d(64,128,3,padding=1), nn.ReLU())
        self.rnn = nn.LSTM(128*8, 64, num_layers=2, batch_first=True, bidirectional=True)
        self.classifier = nn.Linear(128, num_class)
    def forward(self, x):
        y = self.cnn(x).permute(0,3,1,2).flatten(2)
        y, _ = self.rnn(y)
        return self.classifier(y)
'); model=TinyRARE(num_class=37)

